// ─── Helpers ──────────────────────────────────────────────────────────────────

function relativeTime(ts: string | null): string {
  if (!ts) return '';
  const diffS = (Date.now() - new Date(ts).getTime()) / 1000;
  if (diffS < 60)  return `${Math.round(diffS)}s ago`;
  if (diffS < 3600) return `${Math.round(diffS / 60)}m ago`;
  return `${Math.round(diffS / 3600)}h ago`;
}

function goToQueryStore(connId: string, connName: string, queryId: string | null, sqlText: string | null) {
  useQueryStoreNavStore.getState().openQuery({
    connectionId: connId,
    queryId: queryId ?? null,
    sqlText: (sqlText ?? '').trim(),
  });
  openQueryStoreTab({
    connectionId: connId,
    connectionName: connName,
  });
}

function exportItems(items: any[], format: 'csv' | 'json', filterLabel = 'all') {
  const slug = filterLabel === 'all' ? 'all' : filterLabel.replace(/[^a-z0-9]+/gi, '-').toLowerCase();
  const filename = `alerts-${slug}-${new Date().toISOString().slice(0,19).replace(/:/g,'-')}`;
  let content: string;
  let mime: string;
  if (format === 'json') {
    content = JSON.stringify(items, null, 2);
    mime = 'application/json';
  } else {
    const keys = ['severity','category','connection','title','detail','action','ts'];
    const escape = (v: any) => `"${String(v ?? '').replace(/"/g,'""')}"`;
    content = [keys.join(','), ...items.map(r => keys.map(k => escape(r[k])).join(','))].join('\n');
    mime = 'text/csv';
  }
  const a = document.createElement('a');
  a.href = URL.createObjectURL(new Blob([content], { type: mime }));
  a.download = `${filename}.${format}`;
  a.click();
}

// ─── Refresh countdown hook ───────────────────────────────────────────────────
function useCountdown(targetMs: number, isFetching: boolean) {
  const [secs, setSecs] = useState(targetMs / 1000);
  useEffect(() => {
    if (isFetching) { setSecs(targetMs / 1000); return; }
    setSecs(targetMs / 1000);
    const id = setInterval(() => setSecs(s => Math.max(0, s - 1)), 1000);
    return () => clearInterval(id);
  }, [isFetching, targetMs]);
  return secs;
}

// ─── Alert item card ──────────────────────────────────────────────────────────
function AlertCard({
  item, onClose, onAcknowledge, onUnacknowledge, ackPending, onRecommend,
  selectable, selected, onToggleSelect, correlated,
}: {
  item: any;
  onClose: () => void;
  onAcknowledge?: (item: any, intervalSec: number) => void;
  onUnacknowledge?: (item: any) => void;
  ackPending?: boolean;
  onRecommend?: (item: any) => void;
  selectable?: boolean;
  selected?: boolean;
  onToggleSelect?: () => void;
  correlated?: boolean;
}) {
  const isAck = item.category === 'acknowledged';
  const origCat = item.meta?.originalCategory;
  const origMeta = origCat ? (CATEGORY_META[origCat] ?? null) : null;
  const meta   = CATEGORY_META[item.category] ?? { icon: '•', label: item.category, color: '#94a3b8', bg: '#64748b18' };
  const isCrit = !isAck && item.severity === 'critical';

  return (
    <div style={{
      borderRadius: 8,
      border: `1px solid ${correlated ? '#38bdf850' : isAck ? '#10b98140' : isCrit ? '#ef444430' : '#f9731630'}`,
      background: correlated ? '#0ea5e908' : isAck ? '#10b98110' : isCrit ? '#ef444410' : '#f9731610',
      padding: '9px 12px',
      marginBottom: 6,
      display: 'flex',
      gap: 8,
    }}>
      {selectable && (
        <label style={{ display: 'flex', alignItems: 'flex-start', paddingTop: 2, flexShrink: 0, cursor: 'pointer', minWidth: 44, minHeight: 44, justifyContent: 'center' }}>
          <input
            type="checkbox"
            checked={!!selected}
            onChange={onToggleSelect}
            style={{ width: 16, height: 16, cursor: 'pointer', accentColor: 'var(--nv-accent)' }}
          />
        </label>
      )}
      <div style={{ flex: 1, minWidth: 0 }}>
      {/* Row 1: category badge + connection + time */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 5, flexWrap: 'wrap' }}>
        <span style={{ fontSize: 13, lineHeight: 1 }}>{meta.icon}</span>
        <span style={{
          fontSize: 9, fontWeight: 700, padding: '1px 6px', borderRadius: 8,
          background: meta.bg, color: meta.color, border: `1px solid ${meta.color}40`,
        }}>{meta.label}</span>
        {origMeta && (
          <span style={{
            fontSize: 9, fontWeight: 600, padding: '1px 6px', borderRadius: 8,
            background: origMeta.bg, color: origMeta.color, border: `1px solid ${origMeta.color}40`,
          }}>{origMeta.label}</span>
        )}
        {correlated && (
          <span style={{
            fontSize: 8, fontWeight: 700, padding: '1px 5px', borderRadius: 6,
            background: '#0ea5e920', color: '#38bdf8', border: '1px solid #38bdf840',
          }}>linked</span>
        )}
        <span style={{ fontSize: 10, fontWeight: 600, color: 'var(--nv-text)' }}>{item.connection}</span>
        <span style={{ fontSize: 9, color: 'var(--nv-textSubtle)', marginLeft: 'auto' }}>
          {relativeTime(item.ts)}
        </span>
      </div>

      {isAck && (
        <div style={{ fontSize: 9, color: '#34d399', marginBottom: 4, lineHeight: 1.4 }}>
          {item.meta?.stillActive
            ? `👁 Still active · review #${item.meta?.reviewCount ?? 0} · next ${relativeTime(item.meta?.nextReviewAt)}`
            : '✓ Resolved on last review'}
          {item.meta?.acknowledgedBy ? ` · by ${item.meta.acknowledgedBy}` : ''}
        </div>
      )}

      {/* Row 2: title */}
      <p style={{
        fontSize: 11, fontWeight: 600,
        color: isAck ? '#34d399' : isCrit ? '#f87171' : '#fb923c',
        margin: '0 0 4px', lineHeight: 1.4,
      }}>
        {item.title}
      </p>

      {/* Row 3: SQL detail */}
      {item.detail && (
        <p style={{
          fontSize: 10, fontFamily: 'monospace', color: 'var(--nv-textMuted)',
          margin: '0 0 5px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
        }} title={item.detail}>{item.detail}</p>
      )}

      {/* Row 4: action + buttons */}
      <div style={{ display: 'flex', alignItems: 'flex-start', gap: 6, flexWrap: 'wrap' }}>
        <p style={{ fontSize: 9.5, color: 'var(--nv-textSubtle)', flex: 1, margin: 0, lineHeight: 1.4, minWidth: 120 }}>
          💡 {item.action}
        </p>
        <AlertAcknowledgeButton
          item={item}
          pending={ackPending}
          onAcknowledge={onAcknowledge}
          onUnacknowledge={onUnacknowledge}
          compact
        />
        {!isAck && onRecommend && (
          <button
            type="button"
            onClick={() => onRecommend(item)}
            style={{
              display: 'flex', alignItems: 'center', gap: 3, flexShrink: 0,
              padding: '2px 7px', borderRadius: 4, fontSize: 9, fontWeight: 600,
              cursor: 'pointer', background: '#eab30815',
              border: '1px solid #eab30850', color: '#fbbf24',
            }}
          >
            <Lightbulb size={9} />
            Recommend
          </button>
        )}
        {QS_CATEGORIES.has(item.meta?.originalCategory ?? item.category) && item.connId && (
          <button
            type="button"
            onClick={() => {
              goToQueryStore(item.connId, item.connection, item.meta?.queryId ?? null, item.detail ?? null);
              onClose();
            }}
            style={{
              display: 'flex', alignItems: 'center', gap: 3, flexShrink: 0,
              padding: '2px 7px', borderRadius: 4, fontSize: 9, fontWeight: 600,
              cursor: 'pointer', background: '#0ea5e915',
              border: '1px solid #0ea5e940', color: '#38bdf8',
            }}
          >
            <ExternalLink size={9} />
            QS
          </button>
        )}
      </div>
      </div>
    </div>
  );
}

// ─── Main component ───────────────────────────────────────────────────────────
export function AlertsSidebar() {
  const { open, filter, search, toggle, setFilter, setSearch } = useAlertsSidebarStore();
  const isMobile = useIsMobile();
  const openSettings = useSettingsModalStore(s => s.openSettings);
  const { pending: ackPending, acknowledge: handleAcknowledge, unacknowledge: handleUnacknowledge, acknowledgeMany } = useAlertAckActions();
  const [recommendAlert, setRecommendAlert] = useState(null);
  const [forcingPlan, setForcingPlan] = useState(false);
  const [selectedKeys, setSelectedKeys] = useState<Set<string>>(new Set());
  const [showBulkMenu, setShowBulkMenu] = useState(false);
  const [activeCorrelatedGroup, setActiveCorrelatedGroup] = useState<string | null>(null);
  const [refetchMs, setRefetchMs] = useState(() => {
    const prefs = readUiPrefs();
    const sec = Number(prefs.alertsRefetchSec);
    return Number.isFinite(sec) && sec >= 10 ? sec * 1000 : DEFAULT_REFETCH_MS;
  });
  const qc = useQueryClient();

  useEffect(() => {
    const sync = () => {
      const prefs = readUiPrefs();
      const sec = Number(prefs.alertsRefetchSec);
      setRefetchMs(Number.isFinite(sec) && sec >= 10 ? sec * 1000 : DEFAULT_REFETCH_MS);
    };
    sync();
    window.addEventListener('storage', sync);
    window.addEventListener('nv:ui-prefs', sync);
    return () => {
      window.removeEventListener('storage', sync);
      window.removeEventListener('nv:ui-prefs', sync);
    };
  }, []);

  const q = useQuery({
    queryKey: ['dpa-critical-summary'],
    queryFn: () => api.dpaCriticalSummary(),
    staleTime: 25_000,
    refetchInterval: open ? refetchMs : false,
    refetchIntervalInBackground: false,
    ...CACHE_FIRST_QUERY,
  });

  const data  = q.data ?? ({} as any);
  const items: any[] = data.items ?? [];
  const countdown = useCountdown(refetchMs, q.isFetching);

  const visible = items.filter(i => {
    if (activeCorrelatedGroup && i.category !== 'acknowledged') {
      if (i.correlationGroupId !== activeCorrelatedGroup) return false;
    }
    if (filter === 'all') return true;
    // Group filter
    const grp = GROUPS.find(g => g.key === filter);
    if (grp) return grp.cats.includes(i.category);
    return i.category === filter;
  }).filter(i => {
    if (!search) return true;
    return `${i.title} ${i.detail ?? ''} ${i.connection}`.toLowerCase().includes(search.toLowerCase());
  });

  const critCount = data.critical ?? 0;
  const warnCount = data.warnings ?? 0;
  const ackCount  = data.acknowledged ?? items.filter(i => i.category === 'acknowledged').length;
  const openCount = critCount + warnCount;
  const suppressedCount = data.suppressedByBlackout ?? 0;
  const activeBlackouts: any[] = data.blackoutsActive ?? [];
  const correlatedGroups: any[] = data.correlatedGroups ?? [];
  const ackable = visible.filter(i => i.category !== 'acknowledged');
  const selectedCount = ackable.filter(i => selectedKeys.has(i.alertKey ?? '')).length;

  const alertKeyOf = (item: any) => item.alertKey ?? `${item.category}-${item.connId}-${item.title}`;

  // ── New-alert toasts: fire a temporary toast for alerts not seen before ──
  const seenKeys = useRef<Set<string> | null>(null);
  useEffect(() => {
    if (!items.length) {
      if (seenKeys.current) seenKeys.current = new Set();
      return;
    }
    const curKeys = new Set(items.map(alertKeyOf));
    if (seenKeys.current == null) {
      // first load: seed without spamming toasts
      seenKeys.current = curKeys;
      return;
    }
    const newOnes = items.filter(i =>
      i.category !== 'acknowledged' &&
      (i.severity === 'critical' || i.severity === 'warning') &&
      !seenKeys.current!.has(alertKeyOf(i)),
    );
    seenKeys.current = curKeys;
    newOnes.slice(0, 3).forEach(i => {
      const meta = CATEGORY_META[i.meta?.originalCategory ?? i.category] ?? null;
      pushToast({
        title: i.title,
        message: `${i.connection} · ${meta?.label ?? i.category}`,
        icon: <span style={{ fontSize: 14, lineHeight: 1 }}>{meta?.icon ?? '⚠️'}</span>,
        tone: i.severity === 'critical' ? 'danger' : 'warning',
        actionLabel: 'Ver detalle',
        onAction: () => { if (!open) toggle(); },
        duration: 7000,
      });
    });
  }, [data.generatedAt, items.length]);

  useEffect(() => {
    setSelectedKeys(prev => {
      const valid = new Set(ackable.map(alertKeyOf));
      const next = new Set([...prev].filter(k => valid.has(k)));
      return next.size === prev.size ? prev : next;
    });
  }, [visible.length, filter, search]);

  const toggleSelect = (key: string) => {
    setSelectedKeys(prev => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key); else next.add(key);
      return next;
    });
  };

  const selectAllVisible = () => {
    setSelectedKeys(new Set(ackable.map(alertKeyOf)));
  };

  const clearSelection = () => setSelectedKeys(new Set());

  const runBulkAck = async (items: any[], intervalSec: number) => {
    setShowBulkMenu(false);
    await acknowledgeMany(items, intervalSec);
    clearSelection();
  };

  const onForceRecommended = async (planRec, refetch) => {
    const queryId = recommendAlert?.meta?.queryId;
    if (!planRec?.hintSql || !recommendAlert?.connId || !queryId) {
      notify('No hint/query to force plan.');
      return;
    }
    setForcingPlan(true);
    try {
      await api.queryStoreSetForcedPlan(recommendAlert.connId, queryId, planRec.hintSql, true, planRec.planHash);
      notify('Recommended plan forced');
      refetch?.();
      qc.invalidateQueries({ queryKey: ['dpa-critical-summary'] });
    } catch (e) {
      notify(String(e?.message ?? e));
    } finally {
      setForcingPlan(false);
    }
  };

  // ── Collapsed tab ──────────────────────────────────────────────────────────
  const collapsedTab = (
    <div
      onClick={toggle}
      title="Open Alerts Sidebar"
      style={{
        position: 'fixed', right: 0, top: '50%', transform: 'translateY(-50%)',
        zIndex: 1200, cursor: 'pointer',
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        gap: 6, padding: '14px 8px',
        background: critCount > 0 ? '#ef4444' : warnCount > 0 ? '#f97316' : ackCount > 0 ? '#10b981' : 'var(--nv-toolbar)',
        border: `1px solid ${critCount > 0 ? '#ef444480' : warnCount > 0 ? '#f9731680' : ackCount > 0 ? '#10b98180' : 'var(--nv-border)'}`,
        borderRight: 'none', borderRadius: '8px 0 0 8px',
        boxShadow: '-2px 0 12px rgba(0,0,0,0.3)',
        transition: 'background 0.3s',
      }}
    >
      <AlertTriangle size={14} style={{ color: critCount > 0 ? '#fff' : warnCount > 0 ? '#fff' : 'var(--nv-textMuted)' }} />
      {openCount > 0 && (
        <span style={{
          fontSize: 10, fontWeight: 800, color: '#fff',
          background: critCount > 0 ? 'rgba(0,0,0,0.3)' : 'rgba(0,0,0,0.2)',
          borderRadius: 10, padding: '1px 5px', minWidth: 18, textAlign: 'center',
        }}>{openCount}</span>
      )}
      {openCount === 0 && ackCount > 0 && (
        <span style={{
          fontSize: 10, fontWeight: 800, color: '#fff',
          background: 'rgba(0,0,0,0.2)',
          borderRadius: 10, padding: '1px 5px', minWidth: 18, textAlign: 'center',
        }}>{ackCount}</span>
      )}
      <span style={{
        fontSize: 9, fontWeight: 700, letterSpacing: 1,
        color: critCount > 0 ? '#fff' : warnCount > 0 ? '#fff' : 'var(--nv-textMuted)',
        writingMode: 'vertical-rl', transform: 'rotate(180deg)',
      }}>ALERTS</span>
      <ChevronLeft size={12} style={{ color: critCount > 0 ? '#fff' : warnCount > 0 ? '#fff' : 'var(--nv-textMuted)' }} />
    </div>
  );

  // ── Expanded panel ─────────────────────────────────────────────────────────
  const expandedPanel = (
    <div style={{
      position: 'fixed', right: 0, top: 0, bottom: 0,
      width: isMobile ? '100%' : PANEL_WIDTH, zIndex: 1200,
      display: 'flex', flexDirection: 'column',
      background: 'var(--nv-toolbar)',
      border: '1px solid var(--nv-border)',
      borderRight: 'none', borderRadius: isMobile ? 0 : '10px 0 0 10px',
      boxShadow: '-4px 0 32px rgba(0,0,0,0.5)',
    }}>

      {/* ── Header ── */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8,
        padding: '10px 14px', flexShrink: 0,
        borderBottom: '1px solid var(--nv-border)',
        background: critCount > 0 ? '#ef444410' : warnCount > 0 ? '#f9731610' : 'transparent',
      }}>
        <AlertTriangle size={15} style={{ color: critCount > 0 ? '#f87171' : '#fb923c', flexShrink: 0 }} />
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--nv-text)' }}>Live Alerts</div>
          <div style={{ fontSize: 10, color: 'var(--nv-textMuted)', marginTop: 1 }}>
            {q.isFetching
              ? '⟳ Checking all servers…'
              : `${openCount} open${ackCount ? ` · ${ackCount} ack` : ''} · next check in ${Math.round(countdown)}s`}
          </div>
        </div>
        {/* Count badges */}
        <div style={{ display: 'flex', gap: 4 }}>
          {critCount > 0 && (
            <span style={{ fontSize: 10, fontWeight: 800, padding: '2px 7px', borderRadius: 10, background: '#ef4444', color: '#fff' }}>
              {critCount}🔴
            </span>
          )}
          {warnCount > 0 && (
            <span style={{ fontSize: 10, fontWeight: 800, padding: '2px 7px', borderRadius: 10, background: '#f97316', color: '#fff' }}>
              {warnCount}🟠
            </span>
          )}
          {ackCount > 0 && (
            <span style={{ fontSize: 10, fontWeight: 800, padding: '2px 7px', borderRadius: 10, background: '#10b981', color: '#fff' }}>
              {ackCount}✅
            </span>
          )}
        </div>
        {/* Actions */}
        <button type="button" onClick={() => q.refetch()} title="Refresh now"
          style={{ padding: 4, borderRadius: 5, background: 'none', border: 'none', cursor: 'pointer', color: 'var(--nv-textMuted)' }}>
          <RefreshCw size={13} style={{ animation: q.isFetching ? 'spin 1s linear infinite' : 'none' }} />
        </button>
        <button
          type="button"
          title="Clear alerts and re-check from scratch"
          onClick={() => {
            qc.removeQueries({ queryKey: ['dpa-critical-summary'] });
            q.refetch();
          }}
          style={{ padding: 4, borderRadius: 5, background: 'none', border: 'none', cursor: 'pointer', color: 'var(--nv-textMuted)' }}
        >
          <Trash2 size={13} />
        </button>
        {visible.length > 0 && (
          <>
            <button type="button"
              onClick={() => exportItems(visible, 'csv', filter)}
              title={`Export ${filter === 'all' ? 'all alerts' : filter + ' alerts'} as CSV`}
              style={{ padding: 4, borderRadius: 5, background: 'none', border: 'none', cursor: 'pointer', color: 'var(--nv-textMuted)' }}>
              <FileText size={13} />
            </button>
            <button type="button"
              onClick={() => exportItems(visible, 'json', filter)}
              title={`Export ${filter === 'all' ? 'all alerts' : filter + ' alerts'} as JSON`}
              style={{ padding: 4, borderRadius: 5, background: 'none', border: 'none', cursor: 'pointer', color: 'var(--nv-textMuted)' }}>
              <FileJson size={13} />
            </button>
          </>
        )}
        <button type="button" onClick={toggle} title="Collapse"
          style={{ padding: 4, borderRadius: 5, background: 'none', border: 'none', cursor: 'pointer', color: 'var(--nv-textMuted)' }}>
          <ChevronRight size={15} />
        </button>
      </div>

      {/* ── Search ── */}
      <div style={{ padding: '8px 12px', borderBottom: '1px solid var(--nv-border)', flexShrink: 0 }}>
        <input
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search alerts…"
          style={{
            width: '100%', boxSizing: 'border-box',
            padding: '5px 10px', borderRadius: 6, fontSize: 11,
            background: 'var(--nv-surface)', border: '1px solid var(--nv-border)',
            color: 'var(--nv-text)', outline: 'none',
          }}
        />
      </div>

      {/* ── Group filters ── */}
      <div style={{
        display: 'flex', gap: 4, padding: '6px 12px', flexShrink: 0,
        borderBottom: '1px solid var(--nv-border)', flexWrap: 'wrap',
      }}>
        <button type="button" onClick={() => setFilter('all')}
          style={{
            padding: '2px 8px', borderRadius: 10, fontSize: 10, cursor: 'pointer',
            border: '1px solid var(--nv-border)',
            background: filter === 'all' ? 'var(--nv-accent)' : 'var(--nv-surface)',
            color: filter === 'all' ? '#fff' : 'var(--nv-textMuted)',
          }}>All ({items.length})</button>
        {GROUPS.map(g => {
          const cnt = items.filter(i => g.cats.includes(i.category)).length;
          if (!cnt) return null;
          return (
            <button key={g.key} type="button" onClick={() => setFilter(filter === g.key ? 'all' : g.key)}
              style={{
                padding: '2px 8px', borderRadius: 10, fontSize: 10, cursor: 'pointer',
                border: '1px solid var(--nv-border)',
                background: filter === g.key ? 'var(--nv-accent)' : 'var(--nv-surface)',
                color: filter === g.key ? '#fff' : 'var(--nv-textMuted)',
              }}>{g.label} ({cnt})</button>
          );
        })}
      </div>

      {/* ── Bulk actions ── */}
      {ackable.length > 0 && filter !== 'acknowledged' && (
        <div style={{
          display: 'flex', alignItems: 'center', gap: 6, padding: '6px 12px', flexShrink: 0,
          borderBottom: '1px solid var(--nv-border)', flexWrap: 'wrap', background: 'var(--nv-surface)',
        }}>
          <button type="button" onClick={selectAllVisible}
            style={{ fontSize: 10, padding: '4px 8px', borderRadius: 5, cursor: 'pointer', background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)', color: 'var(--nv-textMuted)' }}>
            Select all ({ackable.length})
          </button>
          {selectedCount > 0 && (
            <button type="button" onClick={clearSelection}
              style={{ fontSize: 10, padding: '4px 8px', borderRadius: 5, cursor: 'pointer', background: 'none', border: '1px solid var(--nv-border)', color: 'var(--nv-textMuted)' }}>
              Clear
            </button>
          )}
          <span style={{ fontSize: 10, color: 'var(--nv-textMuted)', flex: 1 }}>
            {selectedCount > 0 ? `${selectedCount} selected · ${ackable.length} visible` : `${ackable.length} open`}
          </span>
          <div style={{ position: 'relative' }}>
            <button type="button" disabled={ackPending}
              onClick={() => setShowBulkMenu(v => !v)}
              style={{
                fontSize: 10, fontWeight: 600, padding: '4px 10px', borderRadius: 5, cursor: ackPending ? 'wait' : 'pointer',
                background: '#10b98115', border: '1px solid #10b98150', color: '#34d399', minHeight: 32,
              }}>
              Acknowledge {selectedCount > 0 ? selectedCount : 'all'}
            </button>
            {showBulkMenu && (
              <AckIntervalMenu
                align="left"
                onClose={() => setShowBulkMenu(false)}
                onSelect={(sec) => {
                  const targets = selectedCount > 0
                    ? ackable.filter(i => selectedKeys.has(alertKeyOf(i)))
                    : ackable;
                  runBulkAck(targets, sec);
                }}
              />
            )}
          </div>
        </div>
      )}

      <CorrelatedIncidentsBanner
        groups={correlatedGroups}
        activeGroupId={activeCorrelatedGroup}
        onSelectGroup={setActiveCorrelatedGroup}
      />

      {/* ── Alert list ── */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '8px 10px' }}>
        {isInitialLoad(q.isLoading, q.data) ? (
          <div style={{ padding: '40px 0', textAlign: 'center', color: 'var(--nv-textMuted)', fontSize: 12 }}>
            <RefreshCw size={20} style={{ animation: 'spin 1s linear infinite', margin: '0 auto 8px', display: 'block' }} />
            Checking all servers…
          </div>
        ) : q.isError ? (
          <div style={{ padding: '40px 8px', textAlign: 'center' }}>
            <div style={{ fontSize: 28, marginBottom: 6 }}>⚠️</div>
            <div style={{ fontSize: 12, color: '#f87171', fontWeight: 600 }}>Could not load alerts</div>
            <button type="button" onClick={() => q.refetch()}
              style={{ marginTop: 10, padding: '4px 12px', borderRadius: 6, fontSize: 11, cursor: 'pointer', background: 'var(--nv-surface)', border: '1px solid var(--nv-border)', color: 'var(--nv-text)' }}>
              Retry
            </button>
          </div>
        ) : visible.length === 0 ? (
          <div style={{ padding: '40px 8px', textAlign: 'center' }}>
            <div style={{ fontSize: 28, marginBottom: 8 }}>✅</div>
            <div style={{ fontSize: 13, fontWeight: 600, color: 'var(--nv-text)' }}>All clear</div>
            <div style={{ fontSize: 10, color: 'var(--nv-textMuted)', marginTop: 4 }}>
              {filter !== 'all' ? 'No alerts in this category' : 'All monitored servers appear healthy'}
            </div>
          </div>
        ) : (
          visible.map((item, idx) => (
            <AlertCard
              key={item.alertKey ?? idx}
              item={item}
              onClose={toggle}
              onAcknowledge={handleAcknowledge}
              onUnacknowledge={handleUnacknowledge}
              ackPending={ackPending}
              onRecommend={setRecommendAlert}
              selectable={item.category !== 'acknowledged' && filter !== 'acknowledged'}
              selected={selectedKeys.has(alertKeyOf(item))}
              onToggleSelect={() => toggleSelect(alertKeyOf(item))}
              correlated={!!item.correlationGroupId}
            />
          ))
        )}
      </div>

      {/* ── Footer ── */}
      <div style={{
        padding: '6px 12px', borderTop: '1px solid var(--nv-border)', flexShrink: 0,
        fontSize: 9, color: 'var(--nv-textSubtle)',
      }}>
        <div style={{ display: 'flex', gap: 6, marginBottom: 6 }}>
          <span>Generated: {data.generatedAt ? relativeTime(data.generatedAt) : '—'}</span>
          <span>·</span>
          <span style={{ flex: 1 }}>Auto-refreshes every {refetchMs / 1000}s</span>
          <span>{data.totalItems ?? 0} total</span>
        </div>
        {(suppressedCount > 0 || activeBlackouts.length > 0) && (
          <div style={{ fontSize: 9, color: '#a78bfa', marginBottom: 4 }}>
            🌙 {suppressedCount > 0 ? `${suppressedCount} alert(s) hidden by blackout` : `${activeBlackouts.length} active blackout(s)`}
          </div>
        )}
        <button
          type="button"
          onClick={() => openSettings('alerts')}
          style={{
            width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5,
            padding: '5px 8px', borderRadius: 6, fontSize: 10, fontWeight: 600, cursor: 'pointer',
            background: 'var(--nv-surface)', border: '1px solid var(--nv-border)', color: 'var(--nv-textMuted)', marginBottom: 4,
          }}
        >
          <Settings2 size={11} />
          Configure alerts
        </button>
        <button
          type="button"
          onClick={() => openSettings('blackouts')}
          style={{
            width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5,
            padding: '5px 8px', borderRadius: 6, fontSize: 10, fontWeight: 600, cursor: 'pointer',
            background: 'var(--nv-surface)', border: '1px solid var(--nv-border)', color: 'var(--nv-textMuted)',
          }}
        >
          <Moon size={11} />
          Maintenance blackouts
        </button>
        <button
          type="button"
          onClick={() => openSettings('general')}
          style={{
            width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5,
            padding: '5px 8px', borderRadius: 6, fontSize: 10, fontWeight: 600, cursor: 'pointer',
            marginTop: 4, background: 'none', border: 'none', color: 'var(--nv-textSubtle)',
          }}
        >
          Open Configuration (Ctrl+,)
        </button>
      </div>
    </div>
  );

  return (
    <>
      <style>{`@keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }`}</style>
      {open ? expandedPanel : collapsedTab}
      <AlertRecommendModal
        open={!!recommendAlert}
        onClose={() => setRecommendAlert(null)}
        alert={recommendAlert}
        onForcePlan={onForceRecommended}
        forcing={forcingPlan}
      />
    </>
  );
}
