// @ts-nocheck
import React, { useState } from 'react';
import { Check, Undo2 } from 'lucide-react';
import { useQueryClient } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { notify } from '../../lib/notify';

export const REVIEW_INTERVALS = [
  { sec: 1800, label: '30 min' },
  { sec: 3600, label: '1 h' },
  { sec: 14400, label: '4 h' },
  { sec: 86400, label: '24 h' },
];

export function useAlertAckActions() {
  const qc = useQueryClient();
  const [pending, setPending] = useState(false);

  const acknowledge = async (item, intervalSec = 3600) => {
    setPending(true);
    try {
      await api.dpaAcknowledgeAlert(item, intervalSec);
      notify(`Acknowledged — re-check in ${REVIEW_INTERVALS.find(o => o.sec === intervalSec)?.label ?? '1 h'}`);
      qc.invalidateQueries({ queryKey: ['dpa-critical-summary'] });
    } catch (e) {
      notify(String(e?.message ?? e));
    } finally {
      setPending(false);
    }
  };

  const unacknowledge = async (item) => {
    const key = item?.alertKey;
    if (!key) return;
    setPending(true);
    try {
      await api.dpaUnacknowledgeAlert(key);
      notify('Alert restored to active list');
      qc.invalidateQueries({ queryKey: ['dpa-critical-summary'] });
    } catch (e) {
      notify(String(e?.message ?? e));
    } finally {
      setPending(false);
    }
  };

  const acknowledgeMany = async (items, intervalSec = 3600) => {
    const alerts = (items ?? []).filter(i => i && i.category !== 'acknowledged');
    if (!alerts.length) return;
    setPending(true);
    try {
      const res = await api.dpaAcknowledgeAlertsBatch(alerts, intervalSec);
      const label = REVIEW_INTERVALS.find(o => o.sec === intervalSec)?.label ?? '1 h';
      notify(`Acknowledged ${res.count ?? alerts.length} alert(s) — re-check in ${label}`);
      qc.invalidateQueries({ queryKey: ['dpa-critical-summary'] });
      return res;
    } catch (e) {
      notify(String(e?.message ?? e));
    } finally {
      setPending(false);
    }
  };

  return { pending, acknowledge, unacknowledge, acknowledgeMany };
}

export function AckIntervalMenu({ onSelect, onClose, align = 'right' }) {
  return (
    <div style={{
      position: 'absolute', [align === 'right' ? 'right' : 'left']: 0, top: '100%', marginTop: 4, zIndex: 10001,
      background: 'var(--nv-toolbar)', border: '1px solid var(--nv-border)',
      borderRadius: 6, padding: 4, minWidth: 110, boxShadow: '0 4px 16px rgba(0,0,0,0.4)',
    }}>
      <div style={{ fontSize: 8, color: 'var(--nv-textMuted)', padding: '2px 6px 4px' }}>Re-check every</div>
      {REVIEW_INTERVALS.map(opt => (
        <button
          key={opt.sec}
          type="button"
          onClick={() => { onClose?.(); onSelect?.(opt.sec); }}
          style={{
            display: 'block', width: '100%', textAlign: 'left',
            padding: '6px 8px', borderRadius: 4, fontSize: 10, cursor: 'pointer',
            background: 'none', border: 'none', color: 'var(--nv-text)', minHeight: 32,
          }}
        >
          {opt.label}
        </button>
      ))}
    </div>
  );
}

export function AlertAcknowledgeButton({ item, pending, onAcknowledge, onUnacknowledge, compact = false }) {
  const isAck = item?.category === 'acknowledged';
  const [showMenu, setShowMenu] = useState(false);

  if (isAck) {
    return (
      <button
        type="button"
        disabled={pending}
        onClick={() => onUnacknowledge?.(item)}
        title="Restore to active alerts"
        style={{
          display: 'flex', alignItems: 'center', gap: compact ? 3 : 4,
          padding: compact ? '2px 7px' : '3px 9px', borderRadius: compact ? 4 : 5,
          fontSize: compact ? 9 : 10, fontWeight: 600, flexShrink: 0,
          cursor: pending ? 'wait' : 'pointer', background: '#64748b15',
          border: '1px solid #64748b50', color: '#94a3b8', opacity: pending ? 0.6 : 1,
        }}
      >
        <Undo2 size={compact ? 9 : 10} />
        Restore
      </button>
    );
  }

  return (
    <div style={{ position: 'relative', flexShrink: 0 }}>
      <button
        type="button"
        disabled={pending}
        onClick={() => setShowMenu(v => !v)}
        title="Acknowledge — re-check later if still active"
        style={{
          display: 'flex', alignItems: 'center', gap: compact ? 3 : 4,
          padding: compact ? '2px 7px' : '3px 9px', borderRadius: compact ? 4 : 5,
          fontSize: compact ? 9 : 10, fontWeight: 600,
          cursor: pending ? 'wait' : 'pointer', background: '#10b98115',
          border: '1px solid #10b98150', color: '#34d399', opacity: pending ? 0.6 : 1,
        }}
      >
        <Check size={compact ? 9 : 10} />
        Acknowledge
      </button>
      {showMenu && (
        <AckIntervalMenu
          onSelect={(sec) => onAcknowledge?.(item, sec)}
          onClose={() => setShowMenu(false)}
        />
      )}
    </div>
  );
}
