// @ts-nocheck
// Shared DPA trends visualization — extracted from DpaObservabilityPanel.tsx.
// Includes the signature stacked-bar WaitTrendChart, SqlRankingTable and
// DimensionBars, plus the color/label helpers they depend on.
// No behavioral changes vs. the original inline definitions.
import { useState } from 'react';
import { Empty } from './helpers';

// ── wait-class hex colors + palette for non-wait dimensions ──────────────────
export const WAIT_HEX: Record<string, string> = {
  CPU: '#ef4444',
  Lock: '#f97316',
  LWLock: '#eab308',
  IO: '#3b82f6',
  BufferPin: '#a855f7',
  Client: '#9ca3af',
  IPC: '#06b6d4',
  Timeout: '#f43f5e',
  Extension: '#22c55e',
  Activity: '#64748b',
  Other: '#0ea5e9',
};
export const WAIT_PALETTE = ['#0ea5e9', '#8b5cf6', '#14b8a6', '#f59e0b', '#ec4899', '#10b981', '#6366f1', '#f43f5e'];

export function classHex(name: string, classes: { name: string }[]) {
  if (WAIT_HEX[name]) return WAIT_HEX[name];
  const idx = classes.findIndex((c) => c.name === name);
  return WAIT_PALETTE[(idx < 0 ? 0 : idx) % WAIT_PALETTE.length];
}

export function fmtBucketLabel(ts: string, windowLabel: string) {
  const d = new Date(ts);
  if (windowLabel === '7d' || windowLabel === '30d') {
    return d.toLocaleDateString([], { month: 'short', day: 'numeric' }) + (windowLabel === '7d' ? ` ${d.getHours()}:00` : '');
  }
  if (windowLabel === '5m' || windowLabel === '15m') {
    return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }
  return d.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
}

export function bucketLabelStep(windowLabel: string, bucketCount: number) {
  if (windowLabel === '5m') return 1;
  if (windowLabel === '15m') return Math.max(1, Math.floor(bucketCount / 15));
  if (windowLabel === '30m') return Math.max(1, Math.floor(bucketCount / 12));
  if (windowLabel === '1h') return Math.max(1, Math.floor(bucketCount / 10));
  return Math.max(1, Math.ceil(bucketCount / 8));
}

export function prettifySql(text: string) {
  return String(text ?? '')
    .replace(/^EXPLAIN\s+(FORMAT\s*=\s*JSON\s+)?/i, '')
    .replace(/\s+/g, ' ')
    .trim();
}

export function entityColor(name: string, entities: {name: string}[], tab?: string) {
  if (!tab || tab === 'waits') return classHex(name, entities);
  const idx = entities.findIndex((e) => e.name === name);
  return WAIT_PALETTE[(idx < 0 ? 0 : idx) % WAIT_PALETTE.length];
}

// ── wait-time trend chart (the DPA signature view) ────────────────────────────
export function WaitTrendChart({
  trends, onEntityClick, highlightEntity, onHighlightEntity, compact = false,
}: {
  trends: any;
  onEntityClick?: (entityName: string, entityLabel: string) => void;
  highlightEntity?: string | null;
  onHighlightEntity?: (entityName: string | null) => void;
  compact?: boolean;
}) {
  const [hoverBucket, setHoverBucket] = useState<number | null>(null);
  const buckets: any[] = trends?.buckets ?? [];
  const tab = trends?.tab ?? 'waits';
  const entities: { name: string; label?: string; total: number }[] = trends?.entities
    ?? (trends?.waitClasses ?? []).map((c: any) => ({ name: c.name, label: c.name, total: c.total }));
  const windowLabel = trends?.window ?? '24h';

  if (!buckets.length) {
    const noHistory = trends?.hasHistory === false;
    return (
      <div className="h-64 flex flex-col items-center justify-center gap-2 border border-dashed border-nv-border rounded-lg bg-nv-surface/40">
        <span className="text-nv-textMuted text-sm">
          {noHistory ? 'Sin historial acumulado para esta instancia' : 'Sin datos de wait time en esta ventana'}
        </span>
        <span className="text-2xs text-nv-textSubtle text-center max-w-md px-4">
          {noHistory
            ? 'El colector DPA guarda snapshots cada minuto. Usa “Snapshot” para la primera muestra o verifica que la conexión sea alcanzable.'
            : 'El colector DPA acumula muestras cada tick. Prueba otra ventana de tiempo o usa “Snapshot”.'}
        </span>
      </div>
    );
  }

  const W = 1000, H = 280;
  const padL = 44, padR = 46, padT = 14, padB = 26;
  const chartW = W - padL - padR;
  const chartH = H - padT - padB;
  const maxTotal = Math.max(...buckets.map((b) => Number(b?.total ?? 0)), 1);
  const barW = Math.max(3, Math.min((chartW / buckets.length) * 0.72, compact ? 28 : 46));
  const svgMinWidth = compact && buckets.length > 12 ? Math.max(W, buckets.length * (barW + 6) + padL + padR) : W;
  const yTicks = [0, 0.25, 0.5, 0.75, 1].map((f) => ({ f, v: maxTotal * f }));
  const plotW = svgMinWidth - padL - padR;
  const plotSlot = plotW / buckets.length;
  const cpuPts = buckets.map((b, i) => {
    const x = padL + plotSlot * (i + 0.5);
    const y = padT + chartH - (Math.min(100, Number(b.cpu ?? 0)) / 100) * chartH;
    return `${x.toFixed(1)},${y.toFixed(1)}`;
  }).join(' ');

  const hb = hoverBucket != null ? buckets[hoverBucket] : null;

  function segmentOpacity(entityName: string) {
    if (!highlightEntity) return 0.95;
    return highlightEntity === entityName ? 1 : 0.18;
  }

  function getBarValue(b: any, name: string) {
    return Number(b.byEntity?.[name] ?? b.byClass?.[name] ?? 0);
  }

  function bucketContributors(b: any) {
    return entities
      .map((ent) => ({ ent, value: getBarValue(b, ent.name) }))
      .filter((x) => x.value > 0)
      .sort((a, b) => b.value - a.value);
  }

  function formatEntityLabel(ent: { name: string; label?: string }) {
    const raw = ent.label ?? ent.name;
    return tab === 'sql' ? prettifySql(raw) : raw;
  }

  function getTopEntityInBucket(b: any) {
    const ranked = bucketContributors(b);
    if (!ranked.length) return { name: '', label: '—', value: 0 };
    const top = ranked[0];
    return {
      name: top.ent.name,
      label: formatEntityLabel(top.ent),
      value: top.value,
      waitClass: top.ent.dominantWaitClass ?? top.ent.name,
    };
  }

  return (
    <div className="relative" onMouseLeave={() => { setHoverBucket(null); onHighlightEntity?.(null); }}>
      <svg
        viewBox={`0 0 ${svgMinWidth} ${H}`}
        width={svgMinWidth}
        height={H}
        className="block max-w-none"
        style={{ minWidth: compact ? svgMinWidth : '100%', width: compact ? svgMinWidth : '100%', height: H }}
        preserveAspectRatio="xMinYMid meet"
      >
        {yTicks.map((t, i) => {
          const y = padT + chartH - t.f * chartH;
          return (
            <g key={i}>
              <line x1={padL} y1={y} x2={svgMinWidth - padR} y2={y} stroke="#1f2937" strokeWidth={1} />
              <text x={padL - 6} y={y + 3} textAnchor="end" fontSize={10} fill="#64748b">{t.v.toFixed(t.v < 10 ? 1 : 0)}</text>
            </g>
          );
        })}
        {buckets.map((b, i) => {
          const x = padL + plotSlot * (i + 0.5) - barW / 2;
          let yCursor = padT + chartH;
          const topInBucket = getTopEntityInBucket(b);
          return (
            <g key={i}>
              {/* Column hover target — full bar height for tooltip */}
              <rect
                x={x - 2}
                y={padT}
                width={barW + 4}
                height={chartH}
                fill="transparent"
                style={{ cursor: onEntityClick ? 'pointer' : 'default' }}
                onMouseEnter={() => {
                  onHighlightEntity?.(topInBucket.name || null);
                  setHoverBucket(i);
                }}
              />
              {entities.map((ent) => {
                const v = getBarValue(b, ent.name);
                if (v <= 0) return null;
                const h = (v / maxTotal) * chartH;
                yCursor -= h;
                const highlighted = highlightEntity === ent.name;
                return (
                  <rect
                    key={ent.name}
                    x={x}
                    y={yCursor}
                    width={barW}
                    height={h}
                    fill={entityColor(ent.name, entities, tab)}
                    opacity={segmentOpacity(ent.name)}
                    stroke={highlighted ? '#f8fafc' : 'none'}
                    strokeWidth={highlighted ? 1.2 : 0}
                    style={{ cursor: onEntityClick ? 'pointer' : 'default' }}
                    onMouseEnter={() => {
                      onHighlightEntity?.(ent.name);
                      setHoverBucket(i);
                    }}
                    onClick={() => onEntityClick?.(ent.name, ent.label ?? ent.name)}
                  />
                );
              })}
            </g>
          );
        })}
        <polyline points={cpuPts} fill="none" stroke="#f87171" strokeWidth={1.5} strokeDasharray="3 2" opacity={0.85} />
        {[0, 50, 100].map((p, i) => {
          const y = padT + chartH - (p / 100) * chartH;
          return <text key={i} x={svgMinWidth - padR + 6} y={y + 3} fontSize={9} fill="#f87171">{p}%</text>;
        })}
        {buckets.map((b, i) => {
          const step = bucketLabelStep(windowLabel, buckets.length);
          if (i % step !== 0 && i !== buckets.length - 1) return null;
          const x = padL + plotSlot * (i + 0.5);
          return <text key={i} x={x} y={H - 8} textAnchor="middle" fontSize={9} fill="#64748b">{fmtBucketLabel(b.ts, windowLabel)}</text>;
        })}
      </svg>

      {hb && (() => {
        const ranked = bucketContributors(hb);
        const top = ranked[0];
        const topLabel = top ? formatEntityLabel(top.ent) : '—';
        const originKind = tab === 'sql' ? 'Query principal' : tab === 'waits' ? 'Wait class principal' : 'Origen principal';
        return (
        <div
          className="absolute z-10 pointer-events-none bg-slate-900/95 border border-nv-border rounded-md p-2 text-2xs shadow-lg min-w-[220px] max-w-[360px]"
          style={{ left: `${Math.min(75, Math.max(4, (hoverBucket! / Math.max(buckets.length - 1, 1)) * 100 - 15))}%`, top: 4 }}
        >
          <div className="text-nv-text font-medium mb-1">{new Date(hb.ts).toLocaleString()}</div>
          <div className="flex justify-between gap-3 mb-1 text-nv-textMuted">
            <span>Total</span><span className="text-sky-300 font-mono">{Number(hb.total ?? 0).toFixed(2)}</span>
          </div>
          {top && (
            <div className="mb-2 p-1.5 rounded bg-red-950/40 border border-red-800/40">
              <div className="text-[9px] uppercase tracking-wide text-red-300 mb-0.5">{originKind}</div>
              <div className="text-[11px] text-nv-text font-medium leading-snug break-words" title={topLabel}>
                {topLabel.slice(0, 120)}{topLabel.length > 120 ? '…' : ''}
              </div>
              <div className="flex justify-between gap-2 mt-1 text-nv-textSubtle">
                <span>{tab === 'waits' ? 'Samples' : 'DB Time'}</span>
                <span className="font-mono text-red-200">{top.value.toFixed(2)}</span>
              </div>
              {top.ent.dominantWaitClass && tab === 'sql' && (
                <div className="text-[9px] text-orange-300 mt-0.5">Wait: {top.ent.dominantWaitClass}</div>
              )}
            </div>
          )}
          <div className="text-[9px] uppercase tracking-wide text-nv-textSubtle mb-1">Desglose</div>
          {ranked.slice(0, 6).map(({ ent, value }) => (
            <div key={ent.name} className={`flex justify-between gap-3 ${highlightEntity === ent.name ? 'text-sky-200 font-semibold' : ''}`}>
              <span className="flex items-center gap-1 truncate max-w-[200px]">
                <span className="inline-block w-2 h-2 rounded-sm shrink-0" style={{ background: entityColor(ent.name, entities, tab) }} />
                <span className="truncate" title={formatEntityLabel(ent)}>
                  {formatEntityLabel(ent).slice(0, 55)}{(formatEntityLabel(ent).length > 55 ? '…' : '')}
                </span>
              </span>
              <span className="font-mono text-nv-textSubtle shrink-0">{value.toFixed(2)}</span>
            </div>
          ))}
          <div className="flex justify-between gap-3 mt-1 pt-1 border-t border-nv-border text-red-300">
            <span>CPU host</span><span className="font-mono">{Number(hb.cpu ?? 0).toFixed(0)}%</span>
          </div>
        </div>
        );
      })()}

      <div className="flex flex-wrap gap-x-3 gap-y-1 mt-2 px-1">
        {tab !== 'sql' && entities.slice(0, 10).map((ent) => (
          <button key={ent.name} type="button" className={`flex items-center gap-1 text-2xs hover:text-nv-text ${highlightEntity === ent.name ? 'text-sky-200 font-semibold' : 'text-nv-textMuted'}`}
            onMouseEnter={() => onHighlightEntity?.(ent.name)}
            onClick={() => onEntityClick?.(ent.name, ent.label ?? ent.name)}>
            <span className="inline-block w-2.5 h-2.5 rounded-sm" style={{ background: entityColor(ent.name, entities, tab) }} />
            <span className="truncate max-w-[120px]">{ent.label ?? ent.name}</span>
            <span className="text-nv-textSubtle font-mono">{Number(ent.total ?? 0).toFixed(1)}</span>
          </button>
        ))}
        {tab === 'sql' && (
          <span className="text-2xs text-nv-textSubtle">Click a bar or use the ranking below → Query Store</span>
        )}
        <span className="flex items-center gap-1 text-2xs text-nv-textMuted ml-auto">
          <span className="inline-block w-3 border-t border-dashed border-red-400" /> CPU host %
        </span>
      </div>
    </div>
  );
}

// ── Top SQL ranking ──────────────────────────────────────────────────────────
export function SqlRankingTable({
  entities, onOpen, highlightEntity, onHighlightEntity,
}: {
  entities: any[];
  onOpen: (id: string, label: string) => void;
  highlightEntity?: string | null;
  onHighlightEntity?: (entityName: string | null) => void;
}) {
  if (!entities.length) return <Empty msg="No SQL samples in this window." />;
  const total = entities.reduce((s, e) => s + Number(e.total ?? 0), 0) || 1;
  return (
    <div className="space-y-2 h-full overflow-y-auto pr-1" onMouseLeave={() => onHighlightEntity?.(null)}>
      {entities.slice(0, 12).map((e, i) => {
        const sql = prettifySql(e.label ?? e.name);
        const pct = (Number(e.total ?? 0) / total) * 100;
        const wait = e.dominantWaitClass ?? 'Other';
        const color = e.color ?? entityColor(e.name, entities, 'sql');
        const active = highlightEntity === e.name;
        return (
          <button key={e.name} type="button" onClick={() => onOpen(String(e.name), sql)}
            onMouseEnter={() => onHighlightEntity?.(e.name)}
            className={`w-full text-left rounded-lg border p-3 transition-all group ${
              active
                ? 'border-sky-500/80 bg-sky-950/45 ring-2 ring-sky-500/40 shadow-md shadow-sky-900/20'
                : 'border-nv-border/60 bg-nv-panel/40 hover:border-sky-600/50 hover:bg-sky-950/25'
            }`}>
            <div className="flex items-center gap-2 mb-2 flex-wrap">
              <span className="text-[10px] font-bold text-nv-textSubtle tabular-nums w-6">#{i + 1}</span>
              <span className="text-[10px] px-1.5 py-0.5 rounded font-medium" style={{ background: `${color}22`, color }}>{wait}</span>
              <span className="text-2xs font-mono text-sky-300 tabular-nums">{pct.toFixed(0)}%</span>
              <span className="text-[10px] text-nv-textSubtle font-mono tabular-nums">{Number(e.total).toFixed(2)} avg active</span>
              <span className="text-[10px] text-sky-400/80 ml-auto opacity-70 group-hover:opacity-100">Go to Query Store ↗</span>
            </div>
            <code className={`block text-[11px] font-mono leading-relaxed break-all line-clamp-3 ${active ? 'text-sky-50' : 'text-nv-text/90 group-hover:text-sky-50'}`}>
              {sql}
            </code>
            <div className="h-1.5 mt-2.5 bg-nv-border/40 rounded-full overflow-hidden">
              <div className="h-full rounded-full transition-all" style={{ width: `${Math.max(pct, 2)}%`, background: color }} />
            </div>
          </button>
        );
      })}
    </div>
  );
}

// ── Generic dimension bars (programs / machines / users / waits) ─────────────
export function DimensionBars({ items, color = '#0ea5e9', emptyMsg, onItemClick, highlightEntity, onHighlightEntity }: {
  items: { label: string; value: number; sub?: string; tone?: string; id?: string }[];
  color?: string;
  emptyMsg?: string;
  onItemClick?: (item: { label: string; value: number; id?: string }, index: number) => void;
  highlightEntity?: string | null;
  onHighlightEntity?: (entityName: string | null) => void;
}) {
  if (!items.length) return <Empty msg={emptyMsg ?? 'No data'} />;
  const max = Math.max(...items.map((i) => i.value), 1);
  const total = items.reduce((s, i) => s + i.value, 0) || 1;
  return (
    <div className="space-y-1.5" onMouseLeave={() => onHighlightEntity?.(null)}>
      {items.map((it, i) => {
        const entityKey = it.id ?? it.label;
        const active = highlightEntity != null && highlightEntity === entityKey;
        return (
        <div key={i} className={`group rounded-md px-1 py-0.5 transition-all ${onItemClick ? 'cursor-pointer' : ''} ${active ? 'bg-sky-950/35 ring-1 ring-sky-500/40' : ''}`}
          onMouseEnter={() => onHighlightEntity?.(entityKey)}
          onClick={() => onItemClick?.(it, i)} role={onItemClick ? 'button' : undefined}>
          <div className="flex items-center justify-between gap-2 mb-0.5">
            <span className={`text-2xs font-mono truncate max-w-[70%] ${active ? 'text-sky-200 font-semibold' : 'text-nv-text group-hover:text-sky-300'}`} title={it.label}>{it.label}</span>
            <span className="text-2xs text-nv-textSubtle font-mono shrink-0">{((it.value / total) * 100).toFixed(0)}%</span>
          </div>
          <div className={`h-3 bg-nv-border/50 rounded-sm overflow-hidden relative ${active ? 'ring-1 ring-sky-500/50' : 'group-hover:ring-1 group-hover:ring-sky-700/40'}`}>
            <div className="h-full rounded-sm transition-all" style={{ width: `${(it.value / max) * 100}%`, background: it.tone ?? color, opacity: active || !highlightEntity ? 1 : 0.35 }} />
            {it.sub && <span className="absolute right-1 top-0 text-[9px] leading-3 text-nv-textSubtle">{it.sub}</span>}
          </div>
        </div>
      );})}
    </div>
  );
}
