// @ts-nocheck
// Shared DPA header bits — extracted from DpaObservabilityPanel.tsx.
// CollectorBadge shows `Collector: healthy · 59s`; SnapshotBtn triggers a
// fresh DPA snapshot. No behavioral changes vs. the original inline definitions.
import { useState } from 'react';
import { RefreshCw } from 'lucide-react';
import { useQuery } from '@tanstack/react-query';
import { api } from '../../../lib/api';
import { DPA_REFETCH_MS } from './helpers';

export function CollectorBadge({ connectionId }: { connectionId: string }) {
  const q = useQuery({
    queryKey: ['dpa-collector-status', connectionId],
    queryFn: () => api.dpaCollectorStatus(connectionId),
    staleTime: 15000,
    refetchInterval: DPA_REFETCH_MS,
    retry: 2,
  });
  if (q.isLoading || (q.isFetching && !q.data)) {
    return (
      <span className="text-[10px] px-2 py-0.5 rounded border text-nv-textMuted border-nv-border/50 bg-nv-surface/40">
        Collector: …
      </span>
    );
  }
  if (q.isError) {
    return (
      <span className="text-[10px] px-2 py-0.5 rounded border text-red-400 border-red-700/50 bg-red-950/30" title={(q.error as Error)?.message ?? ''}>
        Collector: error
      </span>
    );
  }
  const st = q.data?.status ?? 'unknown';
  const color = st === 'healthy' ? 'text-green-400 border-green-700/50 bg-green-950/30'
    : st === 'stale' ? 'text-yellow-400 border-yellow-700/50 bg-yellow-950/30'
      : st === 'unreachable' ? 'text-red-400 border-red-700/50 bg-red-950/30'
        : 'text-orange-400 border-orange-700/50 bg-orange-950/30';
  return (
    <span className={`text-[10px] px-2 py-0.5 rounded border ${color}`} title={q.data?.message ?? ''}>
      Collector: {st}{q.data?.ageSec != null ? ` · ${q.data.ageSec}s` : ''}
    </span>
  );
}

export function SnapshotBtn({ connectionId, onDone }: { connectionId: string; onDone: () => void }) {
  const [running, setRunning] = useState(false);
  async function snap() {
    setRunning(true);
    try {
      await api.dpaSnapshot(connectionId);
      onDone();
    } finally {
      setRunning(false);
    }
  }
  return (
    <button type="button" className="nv-btn !text-2xs" disabled={running} onClick={snap}>
      {running ? '…' : '⟳ Snapshot'}
    </button>
  );
}

// Convenience: a button using the refresh icon glyph (matches the drill header
// variant that renders `<RefreshCw /> Snapshot`). Provided for the DB Tool Box.
export function SnapshotIconButton({ connectionId, onDone }: { connectionId: string; onDone: () => void }) {
  const [running, setRunning] = useState(false);
  async function snap() {
    setRunning(true);
    try {
      await api.dpaSnapshot(connectionId);
      onDone();
    } finally {
      setRunning(false);
    }
  }
  return (
    <button type="button" className="nv-btn !py-0.5 !text-2xs" disabled={running} onClick={snap}>
      <RefreshCw size={11} className="inline mr-1" />Snapshot
    </button>
  );
}
