// @ts-nocheck
// Shared DPA helpers — extracted from DpaObservabilityPanel.tsx so the
// DB Tool Box screen and the legacy DPA panels reuse the same primitives.
// No behavioral changes vs. the original inline definitions.
import type { ReactNode } from 'react';
import { ChevronRight } from 'lucide-react';

// ── Auto-refresh cadences ────────────────────────────────────────────────────
export const DPA_REFETCH_MS = 60_000;         // operational panels: waits, blocking, sessions
export const DPA_SLOW_REFETCH_MS = 120_000;   // analysis panels: trends, workload, advisors

// ── Time window selector ─────────────────────────────────────────────────────
export const WINDOWS = ['5m', '15m', '30m', '1h', '6h', '24h', '7d', '30d'] as const;
export type WindowKey = (typeof WINDOWS)[number];

// ── formatters ───────────────────────────────────────────────────────────────
export function fmtDbTime(sec: number) {
  if (sec >= 3600) return `${(sec / 3600).toFixed(1)}h`;
  if (sec >= 60) return `${(sec / 60).toFixed(1)}m`;
  return `${sec.toFixed(1)}s`;
}

// ── tiny presentational helpers ──────────────────────────────────────────────
export function Loading() {
  return <div className="text-nv-textMuted py-4 text-center">Loading…</div>;
}

export function Empty({ msg = 'No data' }: { msg?: string }) {
  return <div className="text-nv-textSubtle py-8 text-center">{msg}</div>;
}

export function SevBadge({ sev }: { sev: string }) {
  const cls =
    sev === 'high' ? 'bg-red-900/50 text-red-300' :
    sev === 'medium' ? 'bg-orange-900/50 text-orange-300' :
    sev === 'low' ? 'bg-green-900/50 text-green-300' :
    'bg-slate-800 text-slate-400';
  return <span className={`px-1.5 py-0.5 rounded text-2xs font-medium ${cls}`}>{sev}</span>;
}

export function StatCard({ label, value, sub, color = '#0ea5e9', icon }: { label: string; value: string | number; sub?: string; color?: string; icon?: ReactNode }) {
  return (
    <div style={{
      background: 'var(--nv-surface)', border: '1px solid var(--nv-border)',
      borderRadius: 8, padding: '12px 16px', minWidth: 140,
    }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 4 }}>
        {icon && <span style={{ color }}>{icon}</span>}
        <span style={{ fontSize: 10, color: 'var(--nv-textMuted)', textTransform: 'uppercase', letterSpacing: '0.05em' }}>{label}</span>
      </div>
      <div style={{ fontSize: 22, fontWeight: 700, color, lineHeight: 1, fontFamily: 'monospace' }}>{value}</div>
      {sub && <div style={{ fontSize: 10, color: 'var(--nv-textSubtle)', marginTop: 3 }}>{sub}</div>}
    </div>
  );
}

export function NavCard({ icon: Icon, title, desc, onClick, badge }: {
  icon: any; title: string; desc: string; onClick: () => void; badge?: string;
}) {
  return (
    <button type="button" onClick={onClick}
      className="text-left rounded-lg border border-nv-border/60 bg-nv-surface/40 p-3 hover:border-sky-600/50 hover:bg-sky-950/20 transition-all group">
      <div className="flex items-start gap-2">
        <Icon size={16} className="text-sky-400 mt-0.5 shrink-0" />
        <div className="min-w-0 flex-1">
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium text-nv-text group-hover:text-sky-200">{title}</span>
            {badge && <span className="text-[9px] px-1.5 py-0.5 rounded bg-indigo-900/40 text-indigo-300 border border-indigo-700/40">{badge}</span>}
          </div>
          <p className="text-[10px] text-nv-textMuted mt-0.5">{desc}</p>
        </div>
        <ChevronRight size={14} className="text-nv-textSubtle group-hover:text-sky-400 shrink-0 mt-1" />
      </div>
    </button>
  );
}

export function Metric({ label, value, tone }: { label: string; value: any; tone: string }) {
  const color = tone === 'red' ? 'text-red-400' : tone === 'orange' ? 'text-orange-400' : tone === 'green' ? 'text-green-400' : 'text-sky-300';
  return (
    <div className="rounded-md border border-nv-border bg-nv-panel/80 p-2">
      <div className="text-2xs text-nv-textSubtle">{label}</div>
      <div className={`text-lg font-bold font-mono ${color}`}>{value}</div>
    </div>
  );
}
