// @ts-nocheck
import { useQuery } from '@tanstack/react-query';
import { Lightbulb, Pin, RefreshCw, Check } from 'lucide-react';
import { Modal } from '../../components/ui/Modal';
import { SqlScriptActions } from '../../components/sql/SqlScriptActions';
import { api } from '../../lib/api';

function severityClass(severity) {
  if (severity === 'danger') return 'border-red-800/50 bg-red-950/25 text-red-200';
  if (severity === 'warning') return 'border-amber-800/50 bg-amber-950/25 text-amber-200';
  if (severity === 'good') return 'border-emerald-800/50 bg-emerald-950/25 text-emerald-200';
  return 'border-nv-border bg-nv-panel/40 text-nv-text';
}

function fmtSec(v, digits = 2) {
  const n = Number(v ?? 0);
  if (!Number.isFinite(n)) return '—';
  return `${n.toFixed(digits)}s`;
}

function RecBlock({ title, children }) {
  return (
    <section className="space-y-2">
      <div className="text-xs font-semibold text-nv-text">{title}</div>
      {children}
    </section>
  );
}

function RecCard({ item, connectionId, database }) {
  const sqlText = item.sql || item.ddl;
  return (
    <div className={`rounded border p-2.5 space-y-1.5 ${severityClass(item.severity)}`}>
      <div className="text-2xs font-semibold">{item.title}</div>
      <div className="text-2xs text-nv-textSubtle">{item.detail}</div>
      {sqlText && (
        <pre className="text-[10px] font-mono whitespace-pre-wrap break-all p-2 rounded bg-black/20 border border-nv-border/60 max-h-24 overflow-auto">
          {sqlText}
        </pre>
      )}
      {sqlText && (
        <SqlScriptActions
          sql={sqlText}
          connectionId={connectionId}
          database={database ?? item.table}
          copyLabel={item.ddl ? 'Copiar DDL' : 'Copiar'}
        />
      )}
    </div>
  );
}

export function AlertRecommendModal({ open, onClose, alert, onForcePlan, forcing }) {
  const { data, isLoading, refetch } = useQuery({
    queryKey: ['alert-recommendations', alert?.connId, alert?.category, alert?.meta?.queryId, alert?.meta?.pid, alert?.ts],
    queryFn: () => api.dpaAlertRecommendations(alert),
    enabled: open && !!alert?.connId && !!alert?.category,
  });

  if (!open || !alert) return null;

  const summary = data?.summary;
  const plan = data?.plan;
  const indexes = data?.indexes ?? [];
  const actions = data?.actions ?? [];
  const extras = data?.extras ?? [];
  const connectionId = alert.connId;
  const database = alert.meta?.schemaName ?? alert.meta?.schema ?? alert.meta?.database ?? null;

  return (
    <Modal title="Recomendaciones de optimización" onClose={onClose} width="max-w-2xl">
      <div className="text-2xs text-nv-textMuted mb-3 flex items-center gap-2 flex-wrap">
        <Lightbulb size={12} className="text-amber-300" />
        <span className="font-semibold text-nv-text">{alert.connection}</span>
        <span>·</span>
        <span>{alert.title}</span>
      </div>

      {isLoading ? (
        <div className="text-2xs text-nv-textMuted py-8 text-center">
          <RefreshCw size={14} className="animate-spin inline mr-2" /> Analizando alerta…
        </div>
      ) : !data ? (
        <div className="text-2xs text-nv-textMuted py-6 text-center">Sin datos de recomendación.</div>
      ) : (
        <div className="space-y-4 max-h-[70vh] overflow-auto pr-1">
          {summary && (
            <div className={`rounded border p-3 ${severityClass(summary.severity)}`}>
              <div className="text-2xs font-semibold">{summary.title}</div>
              <div className="text-2xs text-nv-textSubtle mt-1">{summary.detail}</div>
            </div>
          )}

          {plan && (
            <RecBlock title="Mejor plan">
              <div className={`rounded border p-3 space-y-2 ${severityClass(plan.severity)}`}>
                <div className="text-2xs font-semibold">{plan.title}</div>
                <div className="text-2xs text-nv-textSubtle">{plan.detail}</div>
                <div className="grid grid-cols-3 gap-2 text-2xs">
                  <div>Avg: <strong>{fmtSec(plan.avgSec, 2)}</strong></div>
                  <div>Exec: <strong>{plan.execCount ?? '—'}</strong></div>
                  {plan.improvementPct != null && (
                    <div>Mejora: <strong>{plan.improvementPct}%</strong></div>
                  )}
                </div>
                {plan.hintSql && (
                  <pre className="text-[10px] font-mono whitespace-pre-wrap break-all p-2 rounded bg-black/20 border border-nv-border/60 max-h-24 overflow-auto">
                    {plan.hintSql}
                  </pre>
                )}
                <div className="flex flex-wrap gap-1">
                  {!plan.isAlreadyForced && plan.canForce && onForcePlan && (
                    <button type="button" className="nv-btn-primary !text-2xs" disabled={forcing} onClick={() => onForcePlan(plan, refetch)}>
                      <Pin size={10} /> Forzar plan recomendado
                    </button>
                  )}
                  {plan.isAlreadyForced && (
                    <span className="text-2xs text-emerald-400 flex items-center gap-1"><Check size={10} /> Plan ya forzado</span>
                  )}
                  {plan.hintSql && (
                    <SqlScriptActions
                      sql={plan.hintSql}
                      connectionId={connectionId}
                      database={database}
                      copyLabel="Copiar hint"
                    />
                  )}
                </div>
              </div>
            </RecBlock>
          )}

          {indexes.length > 0 && (
            <RecBlock title="Índices sugeridos">
              {indexes.map((idx, i) => (
                <RecCard key={`${idx.table}-${i}`} item={idx} connectionId={connectionId} database={database} />
              ))}
            </RecBlock>
          )}

          {actions.length > 0 && (
            <RecBlock title="Acciones recomendadas">
              {actions.filter((a) => a.kind !== 'force_plan').map((a, i) => (
                <RecCard key={i} item={a} connectionId={connectionId} database={database} />
              ))}
            </RecBlock>
          )}

          {extras.length > 0 && (
            <RecBlock title="Recomendaciones adicionales">
              {extras.map((ex, i) => (
                <RecCard key={i} item={ex} connectionId={connectionId} database={database} />
              ))}
            </RecBlock>
          )}

          {!plan && !indexes.length && !actions.length && !extras.length && (
            <div className="text-2xs text-emerald-400 text-center py-4">Sin optimizaciones adicionales — sigue la acción sugerida en la alerta.</div>
          )}
        </div>
      )}
    </Modal>
  );
}
