// @ts-nocheck
/** Correlated incident banners — groups related alerts on the same connection. */
import React from 'react';
import { Link2 } from 'lucide-react';

export function CorrelatedIncidentsBanner({
  groups,
  onSelectGroup,
  activeGroupId,
}: {
  groups: any[];
  onSelectGroup?: (id: string | null) => void;
  activeGroupId?: string | null;
}) {
  if (!groups?.length) return null;

  return (
    <div style={{ padding: '6px 10px 0', flexShrink: 0 }}>
      <div style={{ fontSize: 9, fontWeight: 700, color: 'var(--nv-textMuted)', marginBottom: 4, display: 'flex', alignItems: 'center', gap: 4 }}>
        <Link2 size={10} />
        Correlated incidents ({groups.length})
      </div>
      {groups.map(g => {
        const isCrit = g.severity === 'critical';
        const active = activeGroupId === g.id;
        return (
          <button
            key={g.id}
            type="button"
            onClick={() => onSelectGroup?.(active ? null : g.id)}
            style={{
              width: '100%', textAlign: 'left', marginBottom: 5, padding: '7px 9px', borderRadius: 7,
              cursor: 'pointer',
              border: `1px solid ${active ? '#38bdf880' : isCrit ? '#ef444440' : '#f9731640'}`,
              background: active ? '#0ea5e912' : isCrit ? '#ef444410' : '#f9731610',
            }}
          >
            <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}>
              <span style={{
                fontSize: 8, fontWeight: 800, padding: '1px 5px', borderRadius: 6,
                background: isCrit ? '#ef4444' : '#f97316', color: '#fff',
              }}>
                {g.alertCount} linked
              </span>
              <span style={{ fontSize: 10, fontWeight: 700, color: isCrit ? '#f87171' : '#fb923c', flex: 1 }}>
                {g.title}
              </span>
            </div>
            <div style={{ fontSize: 9, fontWeight: 600, color: 'var(--nv-text)' }}>{g.connection}</div>
            <div style={{ fontSize: 9, color: 'var(--nv-textSubtle)', marginTop: 3, lineHeight: 1.35 }}>
              {g.rootCause}
            </div>
            <div style={{ fontSize: 9, color: '#38bdf8', marginTop: 3 }}>
              💡 {g.action}
            </div>
          </button>
        );
      })}
    </div>
  );
}
